// ─── Per-Tab Proxy ──────────────────────────────────

describe("Per-Tab Proxy", () => {
  let proxyTabId = "";

  test("open with fake proxy", async () => {
    const data: any = await post("/open", { port: PORT, url: "https://httpbin.org/ip", proxy: "http://127.0.0.1:19999" });
    expect(data.tab || data.error).toBeDefined();
    proxyTabId = data.tab?.id || "";
    if (proxyTabId) CREATED_TABS.push(proxyTabId);
  });

  test("tabs shows proxy field", async () => {
    if (!proxyTabId) return;
    const tab = ((await get(`/tabs?port=${PORT}`)) as any).tabs.find((t: any) => t.id === proxyTabId);
    expect(tab?.proxy).toContain("19999");
  });

  test("proxy applied (error page)", async () => {
    if (!proxyTabId) return;
    await Bun.sleep(3000);
    const data: any = await post("/eval", { port: PORT, tabId: proxyTabId, expression: "location.href" });
    expect(data.value).toContain("chrome-error");
  }, 10000);
});

